public int countClumps(int[] nums) {
    // Check for edge cases
    if (nums.length == 0) return 0;

    int clumpCount = 0;
    boolean inClump = false;

    for (int i = 0; i < nums.length - 1; i++) {
        if (nums[i] == nums[i + 1]) {
            if (!inClump) {
                clumpCount++;
                inClump = true;
            }
        } else {
            inClump = false;
        }
    }

    return clumpCount;
}

